class MetadataBuilder:
    """Builds gRPC metadata from HTTP headers and other sources."""

    # Headers that should be forwarded from HTTP to gRPC
    FORWARDED_HEADERS = {
        "x-request-id",
        "x-correlation-id",
        "x-trace-id",
        "x-span-id",
        "authorization",
        "x-api-key",
        "x-client-id",
        "x-client-version",
        "accept-language",
        "x-forwarded-for",
        "x-real-ip",
        "user-agent",
        "x-custom-header",
    }

    # Headers that should never be forwarded
    BLOCKED_HEADERS = {
        "host",
        "content-length",
        "transfer-encoding",
        "connection",
        "keep-alive",
        "upgrade",
    }

    @classmethod
    def build_metadata_from_http_headers(cls, http_headers: dict) -> list:
        """
        Convert HTTP headers to gRPC metadata tuples.
        
        gRPC metadata keys must be lowercase ASCII strings.
        Binary values must use keys ending in '-bin'.
        
        Args:
            http_headers: Dictionary of HTTP headers
            
        Returns:
            List of (key, value) tuples suitable for gRPC metadata
        """
        metadata = []

        for key, value in http_headers.items():
            normalized_key = key.lower().strip()

            # Skip blocked headers
            if normalized_key in cls.BLOCKED_HEADERS:
                continue

            # Only forward known headers or headers with 'x-' prefix
            if normalized_key in cls.FORWARDED_HEADERS or normalized_key.startswith("x-"):
                # gRPC metadata keys must be valid
                sanitized_key = cls._sanitize_metadata_key(normalized_key)
                if sanitized_key:
                    sanitized_value = cls._sanitize_metadata_value(value)
                    metadata.append((sanitized_key, sanitized_value))

        return metadata

    @classmethod
    def build_metadata_from_user_input(cls, user_data: dict) -> list:
        """
        Build gRPC metadata from arbitrary user input/configuration.
        
        Args:
            user_data: Dictionary with user-provided key-value pairs
            
        Returns:
            List of (key, value) tuples for gRPC metadata
        """
        metadata = []

        for key, value in user_data.items():
            sanitized_key = cls._sanitize_metadata_key(key.lower().strip())
            if sanitized_key:
                if isinstance(value, bytes):
                    # Binary metadata must have key ending in '-bin'
                    if not sanitized_key.endswith('-bin'):
                        sanitized_key += '-bin'
                    metadata.append((sanitized_key, value))
                else:
                    sanitized_value = cls._sanitize_metadata_value(str(value))
                    metadata.append((sanitized_key, sanitized_value))

        return metadata

    @classmethod
    def merge_metadata(cls, *metadata_lists) -> list:
        """Merge multiple metadata lists, later entries override earlier ones for same keys."""
        seen = {}
        for metadata_list in metadata_lists:
            for key, value in metadata_list:
                seen[key] = value
        return list(seen.items())

    @staticmethod
    def _sanitize_metadata_key(key: str) -> str:
        """Ensure metadata key is valid for gRPC (lowercase, ASCII, no special chars)."""
        # gRPC metadata keys: lowercase letters, digits, hyphens, underscores, dots
        sanitized = ''.join(c for c in key if c.isalnum() or c in '-_.')
        return sanitized if sanitized else None

    @staticmethod
    def _sanitize_metadata_value(value: str) -> str:
        """Ensure metadata value is valid for gRPC."""
        # Remove non-printable ASCII characters
        return ''.join(c for c in str(value) if 32 <= ord(c) < 127)


