# --- HTTP Gateway Server ---

class APIGatewayHTTPHandler(BaseHTTPRequestHandler):
    """HTTP request handler that forwards requests through the gRPC gateway client."""

    grpc_client = None  # Set by the server

    def do_GET(self):
        self._handle_request("GET")

    def do_POST(self):
        self._handle_request("POST")

    def do_PUT(self):
        self._handle_request("PUT")

    def do_DELETE(self):
        self._handle_request("DELETE")

    def do_PATCH(self):
        self._handle_request("PATCH")

    def _handle_request(self, method):
        """Handle incoming HTTP request and forward via gRPC."""
        # Read request body
        content_length = int(self.headers.get('Content-Length', 0))
        body = self.rfile.read(content_length).decode('utf-8') if content_length > 0 else ""

        # Extract HTTP headers
        http_headers = {}
        for key, value in self.headers.items():
            http_headers[key] = value

        # Parse query parameters for additional user metadata
        parsed_url = urlparse(self.path)
        query_params = parse_qs(parsed_url.query)
        user_metadata = {}
        for key, values in query_params.items():
            if key.startswith("meta_"):
                # Allow users to pass custom metadata via query params: ?meta_key=value
                meta_key = key[5:]  # Remove 'meta_' prefix
                user_metadata[meta_key] = values[0]

        print(f"\n[HTTP Gateway] Received {method} {self.path}")
        print(f"[HTTP Gateway] Headers: {dict(http_headers)}")
        if user_metadata:
            print(f"[HTTP Gateway] User metadata: {user_metadata}")

        # Forward to backend via gRPC
        result = self.grpc_client.forward_request(
            method=method,
            path=parsed_url.path,
            body=body,
            http_headers=http_headers,
            user_metadata=user_metadata
        )

        # Send HTTP response
        self.send_response(result["status_code"])
        self.send_header('Content-Type', 'application/json')

        # Forward backend headers to HTTP response
        for key, value in result.get("headers", {}).items():
            self.send_header(key, value)

        # Include trailing metadata as response headers
        for key, value in result.get("trailing_metadata", {}).items():
            self.send_header(f"x-grpc-{key}", value)

        # Include gRPC status
        self.send_header("x-grpc-status", result.get("grpc_status", "UNKNOWN"))

        response_body = result.get("body", "")
        if isinstance(response_body, str):
            response_body = response_body.encode('utf-8')

        self.send_header('Content-Length', str(len(response_body)))
        self.end_headers()
        self.wfile.write(response_body)

    def log_message(self, format, *args):
        """Custom log format."""
        print(f"[HTTP Gateway] {args[0]}")


