def start_backend_grpc_server(port: int = 50051) -> grpc.Server:
    """Start the backend gRPC server."""
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    server.add_generic_rpc_handlers([BackendServiceHandler()])
    server.add_insecure_port(f'[::]:{port}')
    server.start()
    print(f"[Backend Server] Started on port {port}")
    return server


